from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output
from lfx.schema.message import Message
import json, urllib.request

MCP_URL = "http://host.docker.internal:8765/tool"
OLLAMA_URL = "http://host.docker.internal:11434/api/chat"


def _mcp(tool: str, args: dict) -> dict:
    payload = json.dumps({"tool": tool, "args": args}).encode()
    req = urllib.request.Request(
        MCP_URL, data=payload,
        headers={"Content-Type": "application/json"}, method="POST"
    )
    with urllib.request.urlopen(req, timeout=10) as resp:
        return json.loads(resp.read())


class KGQueryComponent(Component):
    display_name = "Knowledge Graph Query"
    description = "Queries the infrastructure knowledge graph via MCP tool calls"

    inputs = [MessageTextInput(name="diff", display_name="Question", info="Natural language question about the infrastructure")]
    outputs = [Output(display_name="Answer", name="analysis", method="analyse")]

    def analyse(self) -> Message:
        q = self.diff if isinstance(self.diff, str) else str(self.diff)

        # Call MCP read-only tools to assemble context for this query.
        # The LLM receives tool outputs, not raw graph data or credentials.
        ctx_parts = []
        try:
            topo = _mcp("get_environment_topology", {"env_name": "staging"})
            ctx_parts.append("Environment topology:\n" + json.dumps(topo, indent=2))
        except Exception as e:
            ctx_parts.append(f"[topology unavailable: {e}]")

        try:
            svc = _mcp("get_service_context", {"service_name": "sample-backend-api"})
            ctx_parts.append("Service context:\n" + json.dumps(svc, indent=2))
        except Exception as e:
            ctx_parts.append(f"[service context unavailable: {e}]")

        try:
            rb = _mcp("get_runbook", {"runbook_name": "deploy-sample-backend"})
            ctx_parts.append("Deploy runbook:\n" + json.dumps(rb, indent=2))
        except Exception as e:
            ctx_parts.append(f"[runbook unavailable: {e}]")

        kg_context = "\n\n".join(ctx_parts)

        prompt = (
            "You are an infrastructure knowledge assistant. "
            "The following context was retrieved from the infrastructure knowledge graph "
            "via read-only MCP tool calls.\n\n"
            + kg_context
            + "\n\nQuestion: " + q
            + "\n\nAnswer clearly using only information from the retrieved context."
        )

        payload = json.dumps({
            "model": "qwen2.5-coder:7b",
            "messages": [{"role": "user", "content": prompt}],
            "stream": False,
        }).encode()
        req = urllib.request.Request(
            OLLAMA_URL, data=payload,
            headers={"Content-Type": "application/json"}, method="POST"
        )
        try:
            with urllib.request.urlopen(req, timeout=120) as resp:
                return Message(text=json.loads(resp.read()).get("message", {}).get("content", "No response."))
        except Exception as e:
            return Message(text=f"Error: {e}")
